SELECT outcome, COUNT(*) AS number_of_inspection_outcomes
     FROM inspection_outcomes
     GROUP BY outcome;

SELECT COUNT(*) AS failed_inspections
FROM inspection_outcomes
WHERE outcome = 'fail';

SELECT AVG(defects_per_inspection) AS average_defects
FROM (
  SELECT inspection_id, SUM(defect_count) AS defects_per_inspection
  FROM defects
  GROUP BY inspection_id
);

SELECT COUNT(*) 
FROM inspection_outcomes 
WHERE outcome = 'fail';
